using UnityEngine;

/// <summary>
/// Utilitário partilhado para obter o "peso de jogo" de um Collider2D —
/// extraído de <see cref="WeightPlate"/> (Etapa 6.1) para ser reutilizado por
/// outros sistemas baseados em peso (ex: SeesawPlatform, FloatingPlatform).
///
/// Prioridade: ObjectWeight (override explícito) > player (peso da forma
/// actual — AnimalFormData.weightMultiplier) > inimigo (EnemyData.stats.weight,
/// só se 'canPressWeightPlate') > Rigidbody2D.mass (fallback) > 0.
/// </summary>
public static class GameWeightUtil
{
    /// <summary>Peso de jogo de "other", pela prioridade descrita no cabeçalho.</summary>
    public static float GetWeightOf(Collider2D other, float playerFallbackWeight = 1f, bool useRigidbodyMassFallback = true)
    {
        if (other == null) return 0f;

        // 1. Override explícito (caixas, pedras, ou casos especiais em player/inimigo).
        var objectWeight = other.GetComponent<ObjectWeight>();
        if (objectWeight != null) return Mathf.Max(0f, objectWeight.weight);

        // 2. Player: peso da forma animal actual.
        if (other.CompareTag("Player"))
        {
            var switcher = other.GetComponent<FormSwitcher>();
            if (switcher != null && switcher.CurrentForm != null)
                return Mathf.Max(0f, switcher.CurrentForm.weightMultiplier);

            return playerFallbackWeight;
        }

        // 3. Inimigo: peso do EnemyData (só conta se puder pressionar placas de peso).
        var enemy = other.GetComponent<EnemyController>();
        if (enemy != null)
        {
            if (enemy.Data == null || !enemy.Data.weaknesses.canPressWeightPlate || enemy.IsDead) return 0f;
            return Mathf.Max(0f, enemy.Data.stats.weight);
        }

        // 4. Fallback: massa física do Unity.
        if (!useRigidbodyMassFallback) return 0f;

        var rb = other.attachedRigidbody;
        return rb != null ? Mathf.Max(0f, rb.mass) : 0f;
    }

    /// <summary>
    /// Tarefa #6 — Vento (WindZone): peso de "other" para calcular a força do
    /// vento (aceleração = força do vento / peso — quanto mais leve, mais se
    /// desloca). Diferente de <see cref="GetWeightOf"/>:
    ///
    /// - Inimigos contam pelo 'EnemyData.stats.weight' independentemente de
    ///   'canPressWeightPlate' (o vento não é uma placa de peso).
    /// - Nunca devolve 0 (mínimo 0.05) — um peso 0 daria divisão por zero /
    ///   aceleração infinita.
    /// </summary>
    public static float GetWindWeightOf(Collider2D other)
    {
        if (other == null) return 1f;

        var objectWeight = other.GetComponent<ObjectWeight>();
        if (objectWeight != null) return Mathf.Max(0.05f, objectWeight.weight);

        if (other.CompareTag("Player"))
        {
            var switcher = other.GetComponent<FormSwitcher>();
            if (switcher != null && switcher.CurrentForm != null)
                return Mathf.Max(0.05f, switcher.CurrentForm.weightMultiplier);

            return 1f;
        }

        var enemy = other.GetComponent<EnemyController>();
        if (enemy != null && enemy.Data != null)
            return Mathf.Max(0.05f, enemy.Data.stats.weight);

        var rb = other.attachedRigidbody;
        if (rb != null) return Mathf.Max(0.05f, rb.mass);

        return 1f;
    }
}
